example.com {
    @testverify ip 199.115.194.231/32 123.123.123.123/32
    @verified   cookie verified
    @us         geo country US
    classify {age} {
        when @testverify @verified -> 0
        when @us @verified         -> 0
        when @testverify           -> 1
        when @us                   -> 1
        default                    -> 2
    }
    cache_key method host path {age}
    cache_ttl default ttl 1h
    header +cache_status X-Cache
}
